const CheckoutReturn = () => {
  const router = useRouter();
  const [status, setStatus] = useState('loading');
  const [bookingDetails, setBookingDetails] = useState(null);
  const { session_id, booking_id } = router.query;

  useEffect(() => {
    if (!session_id && !booking_id) return;

    const verifyBooking = async () => {
      try {
        const response = await fetch(`/api/bookings/verify`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            sessionId: session_id,
            bookingId: booking_id 
          })
        });

        const result = await response.json();

        if (result.success) {
          setStatus('success');
          setBookingDetails(result.booking);
        } else {
          setStatus('error');
        }
      } catch (error) {
        console.error('Verification error:', error);
        setStatus('error');
      }
    };

    verifyBooking();
  }, [session_id, booking_id]);

  if (status === 'loading') {
    return <div>Verifying your booking...</div>;
  }

  if (status === 'error') {
    return (
      <div>
        <h2>Booking Error</h2>
        <p>There was an issue with your booking. Please contact support.</p>
        <button onClick={() => router.push('/bookings')}>
          Try Again
        </button>
      </div>
    );
  }

  return (
    <div>
      <h2>Booking Confirmed!</h2>
      <div>
        <h3>Booking Details</h3>
        <p>Booking ID: {bookingDetails?.id}</p>
        <p>Date: {bookingDetails?.date}</p>
        <p>Amount: ${bookingDetails?.amount}</p>
      </div>
      <button onClick={() => router.push('/dashboard')}>
