      return {
        ...state,
        reservationCode: action.payload
      };
    case 'CLEAR_RESERVATION_CODE':
      return {
        ...state,
        reservationCode: ''
      };
    case 'LOAD_FROM_SESSION':
      return {
        ...state,
        ...action.payload
      };
    default:
      return state;
  }
};

const initialState = {
  reservationCode: '',
  bookingData: null,
  isLoading: false
};

export const BookingProvider = ({ children }) => {
  const [state, dispatch] = useReducer(bookingReducer, initialState, (initial) => {
    // Initialize from sessionStorage
    try {
      const savedReservationCode = sessionStorage.getItem('reservationCode');
      const savedBookingData = sessionStorage.getItem('bookingData');

      return {
        ...initial,
        reservationCode: savedReservationCode || '',
        bookingData: savedBookingData ? JSON.parse(savedBookingData) : null
      };
    } catch (error) {
      console.warn('Failed to initialize booking state from sessionStorage:', error);
      return initial;
    }
  });

  // Persist reservation code changes
  useEffect(() => {
    try {
      if (state.reservationCode) {
        sessionStorage.setItem('reservationCode', state.reservationCode);
      } else {
        sessionStorage.removeItem('reservationCode');
      }
    } catch (error) {
      console.error('Failed to persist reservation code:', error);
    }
  }, [state.reservationCode]);

  // Persist booking data changes
  useEffect(() => {
    try {
      if (state.bookingData) {
        sessionStorage.setItem('bookingData', JSON.stringify(state.bookingData));
      } else {
        sessionStorage.removeItem('bookingData');
      }
    } catch (error) {
      console.error('Failed to persist booking data:', error);
    }
  }, [state.bookingData]);

  const setReservationCode = (code) => {
    dispatch({ type: 'SET_RESERVATION_CODE', payload: code });
  };

  const clearReservationCode = () => {
    dispatch({ type: 'CLEAR_RESERVATION_CODE' });
  };

  return (
    <BookingContext.Provider value={{
      ...state,
      setReservationCode,
      clearReservationCode
    }}>
      {children}
    </BookingContext.Provider>
  );
};

export const useBooking = () => {
  const context = useContext(BookingContext);
  if (!context) {
    throw new Error('useBooking must be used within a BookingProvider');
  }
  return context;
};
```

### 4. Fix Session Storage Utility

```javascript
// src/utils/sessionStorage.js - NEW UTILITY
export const sessionStorageUtils = {
  // Safe get with fallback
  getItem: (key, fallback = null) => {
    try {
      const item = sessionStorage.getItem(key);
      return item ? JSON.parse(item) : fallback;
    } catch (error) {
      console.warn(`Failed to get ${key} from sessionStorage:`, error);
      return fallback;
    }
  },

  // Safe set with error handling
  setItem: (key, value) => {
    try {
      sessionStorage.setItem(key, JSON.stringify(value));
      return true;
    } catch (error) {
      console.error(`Failed to set ${key} in sessionStorage:`, error);
      return false;
    }
  },

  // Safe remove
  removeItem: (key) => {
    try {
      sessionStorage.removeItem(key);
      return true;
    } catch (error) {
      console.error(`Failed to remove ${key} from sessionStorage:`, error);
      return false;
    }
  },

  // Clear all booking-related data
  clearBookingData: () => {
    const keysToRemove = ['reservationCode', 'bookingData', 'guestInfo'];
    keysToRemove.forEach(key => {
      sessionStorageUtils.removeItem(key);
    });
  }
};
```

