      checkIn: urlSearchParams.get('checkIn') || '',
      checkOut: urlSearchParams.get('checkOut') || '',
      guests: parseInt(urlSearchParams.get('guests')) || 1
    };

    // Only set search params if we have required fields
    if (params.destination && params.checkIn && params.checkOut) {
      setSearchParams(params);
